import re
from collections import defaultdict

# Load the data from files
books_file = locals()['var_functions.query_db:26']
reviews_file = locals()['var_functions.query_db:24']

with open(books_file, 'r') as f:
    books = json.load(f)

with open(reviews_file, 'r') as f:
    reviews = json.load(f)

# Extract publication year from book details
def extract_year(details):
    # Look for year patterns like "2021", "2020", etc.
    match = re.search(r'\b(19\d{2}|20\d{2})\b', details)
    if match:
        return int(match.group(1))
    return None

# Process books to get publication year
book_years = {}
for book in books:
    year = extract_year(book['details'])
    book_years[book['book_id']] = year

# Group reviews by purchase_id (similar to book_id)
reviews_by_book = defaultdict(list)
for review in reviews:
    purchase_id = review['purchase_id']
    # Convert rating to float
    try:
        rating = float(review['rating'])
        reviews_by_book[purchase_id].append(rating)
    except:
        continue

# Calculate average rating per book
book_ratings = {}
for purchase_id, ratings in reviews_by_book.items():
    book_ratings[purchase_id] = sum(ratings) / len(ratings)

# Group books by decade and calculate stats
decade_stats = defaultdict(lambda: {'total_rating': 0, 'book_count': 0, 'books': set()})

for book_id, year in book_years.items():
    if year and book_id in book_ratings:
        decade = (year // 10) * 10
        decade_stats[decade]['total_rating'] += book_ratings[book_id]
        decade_stats[decade]['book_count'] += 1
        decade_stats[decade]['books'].add(book_id)

# Calculate average rating for each decade with at least 10 distinct books
decade_averages = []
for decade, stats in decade_stats.items():
    if stats['book_count'] >= 10:
        avg_rating = stats['total_rating'] / stats['book_count']
        decade_averages.append({
            'decade': f"{decade}s",
            'average_rating': round(avg_rating, 2),
            'book_count': stats['book_count']
        })

# Sort by average rating descending
decade_averages.sort(key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'decades_with_10plus_books': len(decade_averages),
    'top_decades': decade_averages[:5],
    'all_decades': sorted([(d, decade_stats[d]['book_count']) for d in decade_stats], key=lambda x: x[0])
}))"}

