# Get years for all books
book_years = {}
for book in books:
    year = extract_year(book['details'])
    if year:
        book_years[book['book_id']] = year

# Group reviews by purchase_id
reviews_by_book = defaultdict(list)
for review in reviews:
    try:
        rating = float(review['rating'])
        reviews_by_book[review['purchase_id']].append(rating)
    except:
        continue

# Calculate average rating per book
book_ratings = {}
for purchase_id, ratings in reviews_by_book.items():
    if ratings:
        book_ratings[purchase_id] = sum(ratings) / len(ratings)

# Group by decade
decade_stats = defaultdict(lambda: {'total_rating': 0, 'book_count': 0, 'books': set()})

for book_id, year in book_years.items():
    if book_id in book_ratings:
        decade = (year // 10) * 10
        decade_stats[decade]['total_rating'] += book_ratings[book_id]
        decade_stats[decade]['book_count'] += 1
        decade_stats[decade]['books'].add(book_id)

# Calculate averages for decades with at least 10 books
decade_averages = []
for decade, stats in decade_stats.items():
    if stats['book_count'] >= 10:
        avg_rating = stats['total_rating'] / stats['book_count']
        decade_averages.append({
            'decade': f"{decade}s",
            'average_rating': round(avg_rating, 3),
            'book_count': stats['book_count']
        })

# Sort by average rating descending
decade_averages.sort(key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'books_with_years': len(book_years),
    'books_with_ratings': len(book_ratings),
    'matched_books': len(set(book_years.keys()) & set(book_ratings.keys())),
    'decades_found': len(decade_stats),
    'decades_with_10plus': len(decade_averages),
    'top_decade': decade_averages[0] if decade_averages else None,
    'all_decades': decade_averages
}))"}

